import { EstablishmentFines, FoodFineV2 } from './food-fines-v2';

export type PharmaFine = FoodFineV2;

function fixed(l: number, m: number, s: number): EstablishmentFines {
  return {
    large:  { a: l, b: l, c: l, d: l },
    medium: { a: m, b: m, c: m, d: m },
    small:  { a: s, b: s, c: s, d: s },
  };
}
function rangeHi(la: number, lb: number, lc: number, ld: number): EstablishmentFines {
  const mf = 0.9, sf = 0.8;
  return {
    large:  { a: la, b: lb, c: lc, d: ld },
    medium: { a: Math.round(la*mf), b: Math.round(lb*mf), c: Math.round(lc*mf), d: Math.round(ld*mf) },
    small:  { a: Math.round(la*sf), b: Math.round(lb*sf), c: Math.round(lc*sf), d: Math.round(ld*sf) },
  };
}
function rangeLo(la: number, lb: number, lc: number, ld: number): EstablishmentFines {
  const mf = 0.9, sf = 0.8;
  return {
    large:  { a: la, b: lb, c: lc, d: ld },
    medium: { a: Math.round(la*mf), b: Math.round(lb*mf), c: Math.round(lc*mf), d: Math.round(ld*mf) },
    small:  { a: Math.round(la*sf), b: Math.round(lb*sf), c: Math.round(lc*sf), d: Math.round(ld*sf) },
  };
}

